SELECT 
    id, 
    user_id as "userId", 
    status, 
    "stateId", 
    created_at as "createdAt" 
FROM cart


        user_id = #{userId}


        AND status = #{status}


        AND "stateId" = #{stateId}


${orderby} ${pagination}

SELECT id, last_modified_time as "lastModifiedTime" FROM cart
WHERE "stateId" NOT IN ('EXPIRED', 'ORDER_CREATED')
AND last_modified_time < #{lastModifiedTime}

SELECT id, last_modified_time as "lastModifiedTime" FROM cart
WHERE "stateId" = 'CHECKOUT_IN_PROGRESS'
AND last_modified_time < #{lastModifiedTime}

SELECT id, last_modified_time as "lastModifiedTime" FROM cart
WHERE "stateId" = 'PAYMENT_PENDING'
AND last_modified_time < #{lastModifiedTime}
